/**
 * Scope at which a Claude Code plugin can be installed.
 * Mirrors the values stored in `~/.claude/plugins/installed_plugins.json`.
 */
export type InstallScope = "user" | "project" | "local" | "managed";
/**
 * Read `~/.claude/plugins/installed_plugins.json` and return the distinct
 * scopes the given `<plugin>@<marketplace>` key is installed at. Returns an
 * empty array when the file is missing, malformed, or the key is absent —
 * callers should treat that as "scope detection isn't available".
 *
 * `homeDir` overrides `os.homedir()` (for tests).
 */
export declare function detectClaudeInstallScopes(pluginKey: string, homeDir?: string): InstallScope[];
